const raw = $input.first().json;
const b = raw.body ?? raw;
const r = b.respostas ?? {};

const sat = (r.satisfacao_geral ?? '').toLowerCase();
const valor = (r.percepcao_valor ?? '').toLowerCase();
const cont = (r.continuidade ?? '').toLowerCase();

// Semáforo: define se Mayko pode cobrar direto ou deve ligar antes
let semaforo = '🟢 OK — satisfação positiva';
let acao = 'Pode enviar a cobrança da 2ª mensalidade com tranquilidade.';

const vermelho = sat.includes('abaixo')
  || valor.includes('esperava mais')
  || cont.includes('pausar')
  || cont.includes('encerrar');

const amarelo = sat.includes('dentro do esperado')
  || valor.includes('ainda não sei')
  || cont.includes('dúvidas');

if (vermelho) {
  semaforo = '🔴 ATENÇÃO — risco de insatisfação';
  acao = '⚠️ LIGUE para o Rogério ANTES de enviar a cobrança. Resolva o ponto antes do financeiro.';
} else if (amarelo) {
  semaforo = '🟡 MORNO — satisfação neutra';
  acao = 'Considere uma ligação rápida de alinhamento antes da cobrança.';
}

const linhas = [
  '📊 *Pesquisa de Satisfação — Rogério (Advisory)*',
  semaforo,
  '',
  `*Satisfação geral:* ${r.satisfacao_geral ?? 'N/A'}`,
  `*Valor x investimento:* ${r.percepcao_valor ?? 'N/A'}`,
  `*Maior entrega:* ${r.maior_entrega ?? 'N/A'}`,
  `*Comunicação/ritmo:* ${r.comunicacao ?? 'N/A'}`,
  `*Continuidade:* ${r.continuidade ?? 'N/A'}`,
  `*Prioridade próx. mês:* ${r.prioridade_prox_mes ?? 'N/A'}`,
  '',
  `*O que melhorar:* ${r.pode_melhorar || '—'}`,
  `*Mensagem direta:* ${r.mensagem_mayko || '—'}`,
  '',
  `➡️ *Ação sugerida:* ${acao}`,
];

return [{ json: { mensagem: linhas.join('\n'), numero: '5571982170967' } }];
